import { Component, Show } from 'solid-js';

type ConditionalRenderConfig<P> = {
  preRender: keyof P;
  when?: keyof P;
};
/*
preRender sẽ tạo ra DOM ngay lập tức bất kể when có true hay false
 Mặc định false
*/
export function conditionalRender<P extends Record<string, any>>(
  Comp: Component<P>,
  configKey: ConditionalRenderConfig<P>,
) {
  return (p: P) => {
    const preRender = () => p[configKey.preRender] ?? false;
    const whenValue = () => (configKey?.when ? (p[configKey.when] ?? true) : true);

    return preRender() ? (
      <Comp {...p} />
    ) : (
      <Show when={whenValue()} keyed>
        <Comp {...p} />
      </Show>
    );
  };
}
